IMAGO.LoreSnippets["FUN_FACT"] = {
    { text = "Geistheiler sind in Wahrheit abtrünnige Val'kyr." },
    { text = [[Nat Pagle sagte einst: „Man kann sie nicht alle an den Haken bekommen, wenn man nicht auswirft."]] },
